class TestYantraAssist:
    """AI chat assistant panel."""

    @pytest.mark.ai
    def test_yantra_assist_trigger_visible(self, driver):
        navigate(driver, "/dashboard")
        triggers = driver.find_elements(By.CSS_SELECTOR,
            "[data-testid='yantra-assist'], .yantra-assist, "
            "button[aria-label*='assist'], button[aria-label*='chat'], "
            "[class*='assist'], [class*='chat-trigger']"
        )
        # Also look for floating button or AI icon
        if not triggers:
            triggers = driver.find_elements(By.CSS_SELECTOR,
                "button.fixed, .fixed button, [class*='floating']"
            )
        assert len(triggers) >= 1 or "Yantra" in get_body_text(driver), \
            "Yantra Assist trigger button not found"

    @pytest.mark.ai
    def test_yantra_assist_panel_opens(self, driver):
        navigate(driver, "/dashboard")
        # Try to find and click the AI chat trigger
        triggers = driver.find_elements(By.CSS_SELECTOR,
            "[data-testid='yantra-assist'], button[aria-label*='assist'], "
            "button[aria-label*='chat'], [class*='assist'], [class*='chat-trigger'], "
            "button.fixed, .fixed button"
        )
        if triggers:
            safe_click(driver, triggers[-1])  # Last match is often the floating button
            time.sleep(2)
            # Check if a chat panel opened
            text = get_body_text(driver)
            # Panel should show input field or AI-related text
            inputs = driver.find_elements(By.CSS_SELECTOR,
                "textarea, input[placeholder*='ask'], input[placeholder*='message'], "
                "[data-testid='chat-input']"
