        "/repairs", "/complaints", "/asb", "/rent", "/rent/accounts",
        "/rent/arrears", "/compliance", "/compliance/gas",
        "/compliance/electrical", "/compliance/fire",
        "/compliance/awaabs-law", "/communications",
