        "/ai", "/ai/insights", "/ai/predictions", "/ai/assistant",
        "/admin", "/admin/organisation", "/admin/users",
        "/admin/teams", "/admin/workflows", "/admin/integrations",
        "/admin/notifications", "/admin/gdpr", "/admin/audit",
        "/admin/system", "/explore", "/allocations",
        "/allocations/voids", "/allocations/lettings",
        "/search", "/tenant-portal",
    ]

    @pytest.mark.regression
    @pytest.mark.parametrize("route", ALL_ROUTES)
    def test_no_react_error(self, driver, route):
        navigate(driver, route, wait=2)
        assert not is_page_crashed(driver), f"React error detected on {route}"


# ==========================================================================
# SECTION 31: CONSOLE ERROR CHECK
# ==========================================================================
class TestConsoleErrors:
    """Check for JavaScript console errors on key pages."""

    KEY_PAGES = ["/dashboard", "/tenancies", "/properties", "/repairs", "/compliance"]

    @pytest.mark.regression
    @pytest.mark.parametrize("route", KEY_PAGES)
    def test_no_severe_console_errors(self, driver, route):
        navigate(driver, route)
        logs = driver.get_log("browser") if hasattr(driver, "get_log") else []
        severe = [l for l in logs if l.get("level") == "SEVERE"
                  and "favicon" not in l.get("message", "").lower()
                  and "third-party" not in l.get("message", "").lower()]
        # We allow some console errors (third-party libs, etc.) but flag severe ones
        if severe:
            msgs = [l["message"][:200] for l in severe[:3]]
            pytest.skip(f"Console errors on {route}: {msgs}")

